class DeviceConfig { public string Type; public string Name; public double Param; }

var configs = new DeviceConfig[] {
    new DeviceConfig { Type="TempSensor", Name="烘干箱", Param=100 },
    new DeviceConfig { Type="Motor", Name="传送带", Param=3000 },
    new DeviceConfig { Type="TempSensor", Name="冷却塔", Param=50 }
};

void CreateDevice(DeviceConfig c) {
    if (c.Type=="TempSensor") Print($"温度传感器: {c.Name}, 量程{c.Param}°C");
    else if (c.Type=="Motor") Print($"电机: {c.Name}, 最高{c.Param}RPM");
}

foreach (var c in configs) CreateDevice(c);
